from __future__ import annotations

from dataclasses import dataclass

from .models import PortingModule
from .permissions import ToolPermissionContext
from .tools import get_tools


@dataclass(frozen=True)
class ToolPool:
    tools: tuple[PortingModule, ...]
    simple_mode: bool
    include_mcp: bool

    def as_markdown(self) -> str:
        lines = [
            '# Tool Pool',
            '',
            f'Simple mode: {self.simple_mode}',
            f'Include MCP: {self.include_mcp}',
            f'Tool count: {len(self.tools)}',
        ]
        lines.extend(f'- {tool.name} — {tool.source_hint}' for tool in self.tools[:15])
        return '\n'.join(lines)


def assemble_tool_pool(
    simple_mode: bool = False,
    include_mcp: bool = True,
    permission_context: ToolPermissionContext | None = None,
) -> ToolPool:
    return ToolPool(
        tools=get_tools(simple_mode=simple_mode, include_mcp=include_mcp, permission_context=permission_context),
        simple_mode=simple_mode,
        include_mcp=include_mcp,
    )

/**
 * OracleConnector — Bridge to the Remembrance Oracle Toolkit
 *
 * Initializes and manages the connection to the Oracle's core API,
 * providing a focused interface for the Reflector's needs:
 * coherency scoring, covenant checking, pattern lookup, and SERF healing.
 */

const path = require('node:path');
const fs = require('node:fs');
const { sanitizeSerfOutput } = require('./reflector/serfSanitizer');
const { getToolkit: loadToolkit, getPatternLibrary } = require('./reflector/toolkitPool');

function patternStoreDir(baseDir) {
  return path.join(baseDir, '.remembrance');
}

class OracleConnector {
  #oracle = null;
  #config = null;
  #ready = false;

  constructor(config = {}) {
    this.#config = {
      baseDir: config.baseDir || process.cwd(),
      threshold: config.threshold ?? parseFloat(process.env.ORACLE_THRESHOLD || '0.6'),
      autoSeed: config.autoSeed ?? true,
      autoGrow: config.autoGrow ?? false,
      verbose: config.verbose ?? false,
    };
  }

  /** Initialize the Oracle connection */
  async init() {
    const tk = loadToolkit();

    if (tk?.RemembranceOracle) {
      this.#oracle = new tk.RemembranceOracle(this.#config);
      if (typeof this.#oracle.init === 'function') {
        const initTimeout = new Promise((_, reject) =>
          setTimeout(() => reject(new Error('Oracle init timed out after 30s')), 30000)
        );
        await Promise.race([this.#oracle.init(), initTimeout]);
      }
      this.#ready = true;
      return { connected: true, mode: 'full' };
    }

    // Fallback: standalone mode with built-in scoring
    this.#ready = true;
    return { connected: true, mode: 'standalone' };
  }

  get isReady() {
    return this.#ready;
  }

  get mode() {
    return this.#oracle ? 'full' : 'standalone';
  }

  /** Score code coherency using the Oracle's 5-dimension scorer */
  scoreCoherency(code, options = {}) {
    const tk = loadToolkit();

    if (tk?.computeCoherencyScore) {
      return tk.computeCoherencyScore(code, {
        language: options.language || this.#detectLanguage(code, options.filePath),
        testPassed: options.testPassed,
        historicalReliability: options.reliability,
      });
    }

    // Standalone fallback: basic structural scoring
    return this.#fallbackScore(code, options);
  }

  /** Run the Covenant harm filter */
  covenantCheck(code, metadata = {}) {
    const tk = loadToolkit();

    if (tk?.covenantCheck) {
      return tk.covenantCheck(code, metadata);
    }

    // Standalone: always pass (no harm detection without the toolkit)
    return { sealed: true, violations: [], principlesPassed: 15, totalPrinciples: 15 };
  }

  /** Run the SERF reflection loop to heal weak code */
  async reflect(code, options = {}) {
    const tk = loadToolkit();

    if (tk?.reflectionLoop) {
      const result = tk.reflectionLoop(code, {
        language: options.language || this.#detectLanguage(code, options.filePath),
        maxIterations: options.maxIterations ?? 3,
        targetCoherence: options.targetCoherence ?? 0.9,
        ...options,
      });

      // Sanitize SERF output to fix known transform bugs
      if (result.finalCode) {
        result.finalCode = sanitizeSerfOutput(result.finalCode, code);
      }
      if (result.code) {
        result.code = sanitizeSerfOutput(result.code, code);
      }

      return result;
    }

    // Standalone: return code unchanged
    return {
      finalCode: code,
      improved: false,
      iterations: 0,
      reason: 'toolkit-not-available',
    };
  }

  /** Search for proven patterns matching a description */
  async search(query, options = {}) {
    if (this.#oracle) {
      return this.#oracle.search(query, {
        limit: options.limit ?? 5,
        mode: options.mode ?? 'hybrid',
        ...options,
      });
    }
    return [];
  }

  /** Submit validated code to the Oracle's memory */
  async submit(code, metadata = {}) {
    if (this.#oracle) {
      return this.#oracle.submit(code, metadata);
    }
    return { accepted: false, reason: 'toolkit-not-available' };
  }

  /** Get the Oracle's resolve decision (PULL/EVOLVE/GENERATE) */
  async resolve(request) {
    if (this.#oracle) {
      return this.#oracle.resolve(request);
    }
    return { decision: 'generate', confidence: 0, reasoning: 'standalone-mode' };
  }

  /** Get candidate summary with normalized field names (Issue 5 fix).
   *  The toolkit returns { totalCandidates } but for consistency with
   *  summary() which returns { totalPatterns }, we alias it as { total }. */
  async candidateSummary() {
    if (this.#oracle && typeof this.#oracle.candidateSummary === 'function') {
      const result = this.#oracle.candidateSummary();
      if (result && result.totalCandidates !== undefined && result.total === undefined) {
        result.total = result.totalCandidates;
      }
      return result;
    }

    const lib = getPatternLibrary(patternStoreDir(this.#config.baseDir));
    if (lib) {
      try {
        const result = lib.candidateSummary();
        if (result && result.totalCandidates !== undefined && result.total === undefined) {
          result.total = result.totalCandidates;
        }
        return result;
      } catch {
        return { total: 0, totalCandidates: 0, promoted: 0, byLanguage: {}, byMethod: {}, avgCoherency: 0 };
      }
    }

    return { total: 0, totalCandidates: 0, promoted: 0, byLanguage: {}, byMethod: {}, avgCoherency: 0 };
  }

  /** Get Oracle stats */
  async stats() {
    if (this.#oracle) {
      return this.#oracle.stats();
    }
    return { totalEntries: 0, languages: {}, avgCoherency: 0, topTags: [] };
  }

  /** Detect language from code content or file extension */
  #detectLanguage(code, filePath) {
    if (filePath) {
      const ext = path.extname(filePath).toLowerCase();
      const map = {
        '.js': 'javascript', '.mjs': 'javascript', '.cjs': 'javascript',
        '.ts': 'typescript', '.tsx': 'typescript',
        '.py': 'python',
        '.go': 'go',
        '.rs': 'rust',
        '.rb': 'ruby',
        '.java': 'java',
        '.sh': 'bash',
      };
      if (map[ext]) return map[ext];
    }

    const tk = loadToolkit();
    if (tk?.detectLanguage) {
      return tk.detectLanguage(code);
    }

    // Basic heuristic
    if (code.includes('function ') || code.includes('const ') || code.includes('=>')) return 'javascript';
    if (code.includes('def ') && code.includes(':')) return 'python';
    if (code.includes('func ') && code.includes('package ')) return 'go';
    if (code.includes('fn ') && code.includes('let mut')) return 'rust';
    return 'unknown';
  }

  /** Standalone fallback coherency scorer — calibrated to match toolkit dimensions */
  #fallbackScore(code, options = {}) {
    const lines = code.split('\n');
    const nonEmpty = lines.filter(l => l.trim().length > 0);

    // ── Correctness (toolkit: correctness) ──
    // Balanced braces, brackets, and parens
    const openBraces = (code.match(/\{/g) || []).length;
    const closeBraces = (code.match(/\}/g) || []).length;
    const openParens = (code.match(/\(/g) || []).length;
    const closeParens = (code.match(/\)/g) || []).length;
    const openBrackets = (code.match(/\[/g) || []).length;
    const closeBrackets = (code.match(/\]/g) || []).length;
    const braceBalance = Math.abs(openBraces - closeBraces);
    const parenBalance = Math.abs(openParens - closeParens);
    const bracketBalance = Math.abs(openBrackets - closeBrackets);
    const syntaxValid = Math.max(0, 1 - (braceBalance + parenBalance + bracketBalance) * 0.1);

    // Penalize TODOs / FIXMEs (but not ... spread operators)
    const todoCount = (code.match(/\bTODO\b|\bFIXME\b|\bHACK\b|\bXXX\b/gi) || []).length;
    const completeness = Math.max(0, 1 - todoCount * 0.1);
    const correctness = syntaxValid * 0.6 + completeness * 0.4;

    // ── Simplicity (toolkit: simplicity) ──
    // Penalize deep nesting and overly long functions
    let maxDepth = 0;
    let depth = 0;
    for (const ch of code) {
      if (ch === '{') { depth++; maxDepth = Math.max(maxDepth, depth); }
      else if (ch === '}') { depth = Math.max(0, depth - 1); }
    }
    const depthPenalty = Math.max(0, 1 - Math.max(0, maxDepth - 4) * 0.1);
    const avgLineLen = nonEmpty.length > 0 ? nonEmpty.reduce((s, l) => s + l.length, 0) / nonEmpty.length : 0;
    const lineLenPenalty = avgLineLen > 120 ? 0.8 : avgLineLen > 80 ? 0.9 : 1.0;
    const simplicity = depthPenalty * 0.6 + lineLenPenalty * 0.4;

    // ── Readability (toolkit: readability) ──
    // Comment ratio, naming style
    const commentLines = nonEmpty.filter(l => l.trim().startsWith('//') || l.trim().startsWith('*') || l.trim().startsWith('/*')).length;
    const commentRatio = nonEmpty.length > 0 ? commentLines / nonEmpty.length : 0;
    const commentScore = commentRatio >= 0.05 ? 1.0 : commentRatio > 0 ? 0.9 : 0.8;
    const longLines = nonEmpty.filter(l => l.length > 120).length;
    const longLinePenalty = nonEmpty.length > 0 ? Math.max(0, 1 - (longLines / nonEmpty.length) * 0.5) : 1;
    const readability = commentScore * 0.5 + longLinePenalty * 0.5;

    // ── Security (toolkit: security) ──
    let securityScore = 1.0;
    if (/\beval\s*\(/.test(code)) securityScore -= 0.2;
    if (/innerHTML\s*=/.test(code)) securityScore -= 0.1;
    if (/document\.write\s*\(/.test(code)) securityScore -= 0.1;
    if (/new\s+Function\s*\(/.test(code)) securityScore -= 0.2;
    const security = Math.max(0, securityScore);

    // ── Unity (toolkit: unity) ──
    // Indent consistency + naming convention consistency
    const tabLines = nonEmpty.filter(l => l.startsWith('\t')).length;
    const spaceLines = nonEmpty.filter(l => /^ {2,}/.test(l)).length;
    const mixedIndent = tabLines > 0 && spaceLines > 0;
    const consistency = mixedIndent ? 0.6 : 1.0;
    const unity = consistency;

    // ── Composite: equal-weighted 5 dimensions (matches toolkit) ──
    const dimensions = { simplicity, readability, security, unity, correctness };
    const dimValues = Object.values(dimensions);
    const composite = dimValues.reduce((s, v) => s + v, 0) / dimValues.length;

    // Backward-compatible breakdown for existing tests
    return {
      total: Math.round(composite * 1000) / 1000,
      dimensions,
      breakdown: { syntaxValid, completeness, consistency, testProof: options.testPassed === true ? 1.0 : options.testPassed === false ? 0.0 : 0.7, historicalReliability: 0.7 },
      language: options.language || 'unknown',
    };
  }
}

module.exports = { OracleConnector };

